const updateData = $('Normalize Update Data').first().json;
const oldDetails = $('Capture Old Details').first().json;
const eventData = $('Find Event by Email').first().json;
const newStart = new Date(updateData.new_start);
const durationMin = Number(updateData.duration_min) || 60;
const newEnd = updateData.new_end ? new Date(updateData.new_end) : new Date(newStart.getTime() + durationMin * 60000);

const origDesc = eventData.description || '';
const updatedDesc = origDesc + '\nRescheduled: ' + new Date().toISOString().split('T')[0];
const updatedSummary = updateData.updated_title || eventData.event_summary || oldDetails.old_title || 'Appointment';

const formatTime = (isoStr) => {
  if (!isoStr) return 'N/A';
  const d = new Date(isoStr);
  return d.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric', year: 'numeric', timeZone: 'Asia/Manila' })
    + ' at ' + d.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', hour12: true, timeZone: 'Asia/Manila' });
};

return [{
  json: {
    ...oldDetails,
    new_start_iso: newStart.toISOString(),
    new_end_iso: newEnd.toISOString(),
    updated_description: updatedDesc,
    updated_summary: updatedSummary,
    email_old_time: formatTime(oldDetails.old_start),
    email_new_time: formatTime(newStart.toISOString()),
    email_name: updateData.attendee_name || eventData.attendee_name || oldDetails.attendee_name || 'Valued Client',
    email_reason: updateData.reason_for_change || 'as requested',
    booking_id: oldDetails.booking_id || eventData.booking_id || updateData.booking_id || ''
  }
}];

