parameters.jsCode:
const updateData = $('Normalize Update Data').first().json;
const oldDetails = $('Capture Old Details').first().json;
const calResult = $('Update Calendar Event').first().json;
let emailSent = false;
try {
  const emailOutput = $('Send Updated Confirmation Email').first().json;
  emailSent = !!(emailOutput.id || emailOutput.threadId);
} catch(e) { emailSent = false; }
return [{ json: {
  success: true, partial: !emailSent,
  event_id: oldDetails.event_id, booking_id: oldDetails.booking_id,
  old_start: oldDetails.old_start, old_end: oldDetails.old_end,
  new_start: calResult.start ? calResult.start.dateTime : updateData.new_start,
  new_end: calResult.end ? calResult.end.dateTime : updateData.new_end,
  timezone: updateData.timezone, email_sent: emailSent,
  message: emailSent ? 'OK' : 'Email failed'
} }];

const data = $('Normalize Update Data').first().json;
const bookingId = data.booking_id;
const email = data.attendee_email;
const eventIdDirect = data.event_id;

if (eventIdDirect) return [{ json: { event_id: eventIdDirect, found: true, booking_id: bookingId } }];

const events = $input.all().filter(item => {
  if (!item.json?.id) return false;
  const desc = (item.json.description || '').toLowerCase();
  if (bookingId && desc.includes(bookingId.toLowerCase())) return true;
  if (email && desc.includes(email.toLowerCase())) return true;
  return false;
});

if (!events.length) return [{ json: { event_id: '', found: false, booking_id: '' } }];

const ev = events[events.length - 1];
let foundBookingId = bookingId;
if (!foundBookingId) {
  const descMatch = (ev.json.description || '').match(/Booking ID:\s*(BK-[A-Z0-9]+)/i);
  if (descMatch) foundBookingId = descMatch[1];
}

return [{ json: {
  event_id: ev.json.id,
  found: true,
  event_summary: ev.json.summary || '',
  booking_id: foundBookingId || '',
  start_dateTime: ev.json.start?.dateTime || '',
  end_dateTime: ev.json.end?.dateTime || '',
  location: ev.json.location || '',
  description: ev.json.description || ''
} }];

const norm = $('Normalize Update Data').first().json;
const find = $('Find Event by Email').first().json;
const bookingId = norm.booking_id || find.booking_id || '';
const newStart = norm.new_start || '';
return [{ json: {
  'Booking Id': bookingId,
  'Updated Date': new Date().toISOString().split('T')[0],
  'Booking Date': newStart.split('T')[0] || '',
  'Booking Time': newStart.split('T')[1] ? newStart.split('T')[1].substring(0, 5) : '',
  'Booking Status': 'rescheduled'
} }];

